import Foundation

enum AnalyticsEvent: String {
    case appLaunch
    case apiCallStarted = "api_call_started"
    case apiCallFinished = "api_call_finished"
    case userAuthenticated = "user_authenticated"
    case userDataChanged = "user_data_changed"
    case errorOccurred = "error_occurred"
}

struct AnalyticsLogger {
    static func log(event: AnalyticsEvent, message: Any? = nil) {
        print("[\(Date().description)] [\(event.rawValue)] \(message ?? "")")
    }

    // Track API calls
    static func trackAPICall(_ request: URLRequest, startTime: TimeInterval, response: URLResponse?, data: Data?, error: Error?) {
        let apiCallDuration = Date().timeIntervalSince(Date(timeIntervalSince1970: startTime))
        AnalyticsLogger.log(event: .apiCallFinished)
        if let requestURL = request.url, let httpResponse = response as? HTTPURLResponse {
            AnalyticsLogger.log(event: .apiCallStarted, message: ["request_url": requestURL.absoluteString, "status_code": httpResponse.statusCode])
        }
        if let data = data {
            if let stringData = String(data: data, encoding: .utf8) {
                AnalyticsLogger.log(event: .apiCallFinished, message: ["response_payload": stringData])
            }
        }
        if let error = error {
            AnalyticsLogger.log(event: .errorOccurred, message: ["error_message": error.localizedDescription])
        }
    }
}